/**
 * Hook replacement for the legacy this.state pattern.
 * Previously components used this.state = { count: 0 } and
 * this.setState({ count: 1 }) in class components.
 * This hook provides the same capability without a class.
 */
function useCount(initial = 0) {
  const [count, setCount] = useState(initial);
  return { count, setCount };
}
